{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires reconstructing a sequence of operations. This involves understanding the structural changes between the initial and final trees, specifically identifying which sibling groups were merged and in what order. I will break this into structural analysis, operation identification, and sequence validation.",
  "helpers": [
    {
      "label": "structural_analyzer",
      "instructions": "Compare the initial tree and the final tree. For every node in the final tree, identify its set of children. Map these children back to the original tree to determine which original nodes (or groups of original nodes) were merged to form each child in the final tree. Identify the specific sibling groups in the initial tree that were collapsed into single nodes in the final tree."
    },
    {
      "label": "operation_sequencer",
      "instructions": "Based on the mapping of original nodes to final nodes, determine the order of merge operations. A merge operation on a set of siblings must occur such that the resulting node can then participate in subsequent merges or become a child in the final tree. Identify the dependencies: if node A is a descendant of node B in the final tree, the merges forming A must happen before the merges forming B. List the required merge operations (which siblings are merged) in a valid topological order."
    },
    {
      "label": "validity_checker",
      "instructions": "Given a proposed sequence of merge operations, simulate the process starting from the initial tree. Verify that each operation is valid (merging siblings) and that the resulting tree structure matches the target final tree exactly. Ensure no illegal operations are performed and all required merges are accounted for."
    }
  ],
  "synthesis_brief": "Combine the structural mapping from the analyzer with the dependency-based ordering from the sequencer to produce a candidate sequence. Use the validity checker to confirm the sequence is correct and meets all problem constraints."
}

